Here's a modern MSTest test class for your `DataFetcher`:

```csharp
using System.Net;
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello world"),
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler(
            new HttpResponseMessage(HttpStatusCode.NotFound));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_Cancelled_ThrowsOperationCanceled()
    {
        // Arrange — handler that delays long enough for cancellation
        var handler = new FakeHandler(async (_, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(30), ct);
            return new HttpResponseMessage(HttpStatusCode.OK);
        });
        var fetcher = new DataFetcher(new HttpClient(handler));
        using var cts = CancellationTokenSource.CreateLinkedTokenSource(
            _testContext.CancellationToken);

        // Act & Assert
        cts.CancelAfter(TimeSpan.FromMilliseconds(50));
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_AlreadyCancelled_ThrowsImmediately()
    {
        var handler = new FakeHandler(
            new HttpResponseMessage(HttpStatusCode.OK));
        var fetcher = new DataFetcher(new HttpClient(handler));
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // already cancelled

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    /// <summary>
    /// Minimal fake HttpMessageHandler for testing without external mocking libraries.
    /// </summary>
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> _send;

        public FakeHandler(HttpResponseMessage fixedResponse)
            : this((_, _) => Task.FromResult(fixedResponse)) { }

        public FakeHandler(
            Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> send)
            => _send = send;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => _send(request, cancellationToken);
    }
}
```

**Key patterns used:**

| Pattern | How |
|---|---|
| **Async tests** | `async Task` return type — MSTest awaits natively |
| **Timeouts** | `[Timeout(5000)]` — test fails if it hangs |
| **CancellationToken** | `_testContext.CancellationToken` — linked to `[Timeout]` so the token fires on timeout |
| **Cancellation testing** | `CreateLinkedTokenSource` chains the test timeout with a short `CancelAfter` |
| **Exception testing** | `Assert.ThrowsExactlyAsync` instead of `[ExpectedException]` |
| **Sealed class** | Performance + design clarity |
| **Constructor injection** | `TestContext` via constructor (MSTest 3.6+) enables `readonly` fields |

The `FakeHandler` avoids a mocking library dependency — it accepts either a fixed response or a delegate for dynamic behavior like simulating delays.
